-- ============================================================================
-- 2026-06-29: seed engine_bug_queue with the renderer-side prevention rules from
-- BUILDING the dipole_potential field_3d primitives (electric_potential_dipole,
-- V = k p cosθ/r²). Generated by
-- src/scripts/_seed_engine_bug_queue_dipole_potential_build.ts — idempotent.
-- ============================================================================

INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('field3d_scenario_union_member_without_builder_renders_nothing', 'A scenario_type union member declared with NO build switch case + builder renders an empty canvas — the JSON validator + tsc PASS while the sim is blank, because nothing dispatches to a builder for that scenario', 'CRITICAL', 'peter_parker:renderer_primitives', 'dipole_potential was added to the Field3DConfig.scenario_type union (so authoring + Zod + tsc all passed) but the build switch had no `case "dipole_potential"`, no buildDipolePotential(), no applyDipolePotentialState(), and no updateDipolePotentialFrame() — so electric_potential_dipole rendered nothing. Type-level membership is not a renderer.', 'Every scenario_type union member ships, in the SAME change, a build switch case → buildX(config) (reads the authored field_3d_config, not config_unused), an authoritative applyXState() (after the generic visible_elements matcher), an accumulator-free updateXFrame() on the state clock wired into animate(), the freeze accumulator-free snap list, and the deriveStateMeta registration. A union member with no builder is a build incident, not a content bug.', 'manual', 'Open electric_potential_dipole STATE_1..STATE_7: each must render the +q/-q pair + p arrow; S1 probe + r₊/r₋ lines + two-term callout + signed V; S2 θ-arc + collapsed V=kp cosθ/r²; S3 probe sweeps 40→140° and V recolors + flips sign across cosθ=0; S4 translucent equatorial disc reading V=0 with a persistent green E arrow antiparallel to p; S5 V-vs-θ cosine panel with a live dot; S6 V-vs-1/r² bright dipole diving below the dimmed 1/r ghost crossing at r=1; S7 θ/r sliders + draggable probe + live signed V + equipotential lobes.', 'FIXED', ARRAY['electric_potential_dipole'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-29_electric_potential_dipole_build', 'incident'),
('dp_potential_is_signed_scalar_no_arrow', 'The dipole potential V is a SIGNED SCALAR — the readout must change sign + recolor (positive_color → zero_color → negative_color) as the probe crosses cosθ=0, and must NEVER draw a direction arrow (sign_recolor.draws_arrow:false, Rule 24)', 'MAJOR', 'peter_parker:renderer_primitives', 'Reusing a vector/field-arrow rendering for a potential would imply V has a direction; and a magnitude-only readout would lose the sign that is the entire STATE_3 teaching beat (the sign follows position via cosθ, not the sign of the nearby charge).', 'The V readout is a billboard NUMBER (updateLabelSpriteText, glyph height constant — Rule 29) showing a leading +/− sign; in show_sign_recolor states the sprite colour is set from sign_recolor.{positive,zero,negative}_color by sign of V (zero band near |V|<threshold). No arrow primitive is ever drawn for V.', 'manual', 'STATE_3: as the probe sweeps from the +q side to the −q side at fixed r, the V readout starts red/positive, passes through the zero colour near θ=90°, and ends blue/negative — and no arrow ever appears on V.', 'FIXED', ARRAY['electric_potential_dipole'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-29_electric_potential_dipole_build', 'incident'),
('dp_equatorial_disc_v_zero_with_nonzero_E_simultaneous', 'STATE_4 (PRIMARY aha): the translucent equatorial disc (θ=90°, ⊥ axis) must read V=0 at ≥3 sample points AND show a persistent non-zero E arrow (green, antiparallel to p) AT THE SAME TIME — the V=0 / E≠0 contrast IS the aha and both must be visible together', 'MAJOR', 'peter_parker:renderer_primitives', 'If the disc V=0 label and the E arrow are sequenced so only one shows at the frozen payoff, or the E arrow is computed from V (and so collapses to zero on the equator), the central "scalar zero but vector non-zero" contrast is lost.', 'The disc is a translucent CircleGeometry with normal along the dipole axis (rotation.y=π/2 so it lies in the plane ⊥ p), placed through the centre; ≥3 sample dots + a V=0 label fade in at disc_v_at_ms and HOLD; a fixed-direction green E arrow (antiparallel to p, length from E_equatorial_demo, NOT from V) fades in at e_arrow_at_ms and HOLDS. Both end poses persist to the frozen payoff frame.', 'manual', 'STATE_4 at its pinned reveal: the disc is visible with V=0, three dots on it, AND a green E arrow pointing antiparallel to p — all on screen simultaneously.', 'FIXED', ARRAY['electric_potential_dipole'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-29_electric_potential_dipole_build', 'incident'),
('dp_falloff_curve_dipole_1_over_r2_below_point_1_over_r', 'STATE_6 falloff panel: the BRIGHT dipole curve (V ∝ 1/r²) must dive BELOW the DIMMED point-charge ghost (V ∝ 1/r), the two crossing at r=meet_at_r (=1) — the faster dipole falloff is the payoff and the curves must be computed from the closed forms, not faked', 'MAJOR', 'peter_parker:renderer_primitives', 'Hand-tuned curve shapes (or both curves using the same falloff) hide the 1/r² vs 1/r divergence; a draw cue that never completes leaves the panel mid-sweep at the frozen frame.', 'Both curves are sampled from the demo closed forms — bright = V_dipole_demo (vp/r²), dim dashed = V_point_ghost_demo (vp/r) — on the same axes; the left→right draw sweep is a pure function of (time - stateStartTime) from curve_draw_at_ms; the ghost fades in at ghost_fade_at_ms; a crossover tick marks meet_at_r. Slider/explore states render both at full immediately (no draw cue). A live dot rides the bright curve at the live r.', 'manual', 'STATE_6 at its pin: the bright cyan dipole curve sits ABOVE the dim green dashed ghost for r<1, the two cross at r=1, and the bright curve drops BELOW the ghost for r>1; a crossover tick reads r=1.', 'FIXED', ARRAY['electric_potential_dipole'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-29_electric_potential_dipole_build', 'incident'),
('dp_equipotential_lobes_flat_2d_slice_contour_not_3d_surface', 'STATE_7 equipotential lobes must be flat 2D contour LINES in the dipole-axis slice plane (mode 2d_slice_contour), NOT 3D tessellated surfaces — founder lean lock', 'MODERATE', 'peter_parker:renderer_primitives', 'A naive equipotential visualisation tessellates a 3D iso-surface, which is heavy and off-spec; the lean lock requires flat slice-plane contour loops.', 'Each authored level c is a closed loop in the XY slice computed from the far-field form r(θ)=sqrt(vp·p·cosθ/|c|) over the half-plane where cosθ matches sign(c) (mirrored for the negative lobe), clamped to a max radius, drawn as a thin tube/line (positive_color for c>0, negative_color for c<0). No 3D surface geometry.', 'manual', 'STATE_7: the equipotential lobes are flat figure-eight-style contour loops lying in the dipole-axis plane (red lobes around +q, blue around −q), not shaded 3D shells.', 'FIXED', ARRAY['electric_potential_dipole'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-29_electric_potential_dipole_build', 'incident'),
('dp_devstatemeta_potential_dipole_block_registered_same_change', 'electric_potential_dipole per-state `potential` reveal keys must be registered in deriveStateMeta in the SAME change (else THE EYE classifies every state at the 1500ms default and false-fails the late reveals + the STATE_3/5 sweeps + the STATE_7 interactive state)', 'MAJOR', 'peter_parker:renderer_primitives', 'A new field_3d arc whose per-state `potential` keys (two_term_at_ms, v_readout_at_ms, theta_arc_at_ms, formula_callout_at_ms, sweep{at_ms,duration_ms}, disc_at_ms, disc_v_at_ms, e_arrow_at_ms, v_theta_curve_at_ms, theta_sweep{at_ms,duration_ms}, curve_draw_at_ms, ghost_fade_at_ms, split_highlight_at_ms, draggable_probe) are not recognised by deriveStateMeta classifies at the 1500ms default → D7/D1p false-fail (the field3d_scenario_missing_devstatemeta_recognition scar).', 'Add the dipole `potential` keys to deriveStateMeta in the SAME change: F3D_REVEAL_KEYS includes "potential"; maxRevealForField3dState pins past every *_at_ms beat AND the sweep/theta_sweep END; deriveMotionExpectations marks STATE_3 (sweep) + STATE_5 (theta_sweep) MOTION; deriveHoldExpectations marks STATE_7 (draggable_probe / show_sliders) interactive, STATE_3/5 strict (undefined), and the one-shot reveal states (1/2/4/6) reveal_hold.', 'manual', 'Run visual:eyes on electric_potential_dipole; classifications must be S1=reveal_hold(13100) S2=reveal_hold(6900) S3=motion(13000) S4=reveal_hold(17000) S5=motion(11000) S6=reveal_hold(10700) S7=interactive — none at the bare 1500ms default for the reveal states. VERIFIED via deriveMaxRevealTimeMs/deriveHoldExpectations/deriveMotionExpectations on the concept JSON.', 'FIXED', ARRAY['electric_potential_dipole'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-29_electric_potential_dipole_build', 'incident')
ON CONFLICT (bug_class) DO UPDATE SET
  title = EXCLUDED.title, severity = EXCLUDED.severity, owner_cluster = EXCLUDED.owner_cluster,
  root_cause = EXCLUDED.root_cause, prevention_rule = EXCLUDED.prevention_rule,
  probe_type = EXCLUDED.probe_type, probe_logic = EXCLUDED.probe_logic,
  status = EXCLUDED.status, concepts_affected = EXCLUDED.concepts_affected,
  fixed_in_files = EXCLUDED.fixed_in_files, row_type = EXCLUDED.row_type;
